-- Targeted migration: re-tag + top up CompTIA Server+ SK0-005-P1..P4.
-- Prod was at original seeds (~36-41/variant), domains skewed to
-- "Server Administration" with some domains at 0. This:
--   1. Re-tags every existing question to its correct domain
--   2. Idempotently inserts all questions missing on prod (prior local
--      top-up that never shipped + 120 new) as DRAFT, correctly tagged
--   3. Sets Exam.questionCount = 90 (official SK0-005 length)
-- Blueprint: SvrHW 17 | SvrAdmin 30 | Sec&DR 24 | Troubleshoot 29.
-- Keyed on (Exam.code + stem); idempotent; never touches published/deletedAt.

CREATE EXTENSION IF NOT EXISTS pgcrypto;

