INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your server room consists of 2 tower servers and 12 rack-mounted servers. Local console access is required for each of the 14 servers. The server room cannot accommodate 14 monitors, keyboards, and mice. Which solution should you employ?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"iDRAC"},{"id":"B","text":"iLO"},{"id":"C","text":"UPS"},{"id":"D","text":"KVM"}]$patch$::jsonb, $patch$["D"]$patch$::jsonb, $patch$Correct Answer: KVM is correct. Keyboard, video, mouse (KVM) enables multiple servers to share a single monitor, keyboard, and mouse.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P1$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your server room consists of 2 tower servers and 12 rack-mounted servers. Local console access is required for each of the 14 servers. The server room cannot accommodate 14 monitors, keyboards, and mice. Which solution should you employ?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$While configuring cloud virtual machine disks for a heavily loaded database, you notice that you are maxing out your IOPS. You see an option to increase IOPS. What will this result in besides higher usage fees?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Increased disk space"},{"id":"B","text":"Increased security"},{"id":"C","text":"Increased replication sites"},{"id":"D","text":"Increased performance"}]$patch$::jsonb, $patch$["D"]$patch$::jsonb, $patch$Correct Answer: Increased performance is correct. An increase of input/output operations per second (IOPS) means better disk performance.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
