INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which solution provides Internet access to multiple virtualized network clients using a single public IP address?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Static NAT"},{"id":"B","text":"Reverse proxy"},{"id":"C","text":"PAT"},{"id":"D","text":"Packet filtering firewall"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: PAT is correct. Port address translation (PAT) enables internal clients to access the Internet using the public IP address of the PAT device. Clients must use the internal PAT IP address as their default gateway setting.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
