INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Linux command sets the local computer name?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"`computernamectl`"},{"id":"B","text":"`hostnameconfig`"},{"id":"C","text":"`computername`"},{"id":"D","text":"`hostnamectl`"}]$patch$::jsonb, $patch$["D"]$patch$::jsonb, $patch$Correct Answer: `hostnamectl` is correct. The Linux hostname can be set with the `hostnamectl` command.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
