INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following are not examples of hardening a server? (Choose two.)$patch$, 'MULTI'::"QType", $patch$[{"id":"A","text":"Opening additional ports to make attackers guess what ports your services are on"},{"id":"B","text":"Enabling all available services"},{"id":"C","text":"Closing unneeded ports"},{"id":"D","text":"Installing the latest patches"}]$patch$::jsonb, $patch$["B"]$patch$::jsonb, $patch$Correct Answers: Enabling all available services and opening additional ports to make attackers guess what ports your services are on are correct. Enabling all available services and opening additional ports as a distraction are not valid hardening techniques.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
