INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$One of your firewall appliances is an old tower server with two PCI 32-bit NICs. One of the NICs fails. Which item can be used to replace the failed server NIC?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"FC HBA"},{"id":"B","text":"64-bit PCI NIC"},{"id":"C","text":"NIC teaming"},{"id":"D","text":"Virtual NIC"}]$patch$::jsonb, $patch$["B"]$patch$::jsonb, $patch$Correct Answer: 64-bit PCI NIC is correct. 64-bit PCI cards can be plugged into 32-bit PCI motherboard slots.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
