INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which term is used to describe the amount of time it takes to repair a failed device?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"RPO"},{"id":"B","text":"MTTR"},{"id":"C","text":"BCP"},{"id":"D","text":"RTO"}]$patch$::jsonb, $patch$["B"]$patch$::jsonb, $patch$Correct Answer: MTTR is correct. The mean time to repair (MTTR) is the average amount of time it takes to fix a failed device.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
