  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You are looking to license a piece of software on a server with 64 CPU cores in one socket. What kind of licensing model would most likely be more expensive?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which option provides the quickest way to reverse the installation of a problematic driver?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Bare-metal restoration"},{"id":"B","text":"Driver rollback"},{"id":"C","text":"Virtual machine snapshot"},{"id":"D","text":"System restore point"}]$patch$::jsonb, $patch$["B"]$patch$::jsonb, $patch$Correct Answer: Driver rollback is correct. Driver rollback reverts to the previous driver.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
