INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$While capturing network traffic, you notice excessive port 25 traffic leaving the network. What could this indicate?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"DoS attack against SNMP"},{"id":"B","text":"Cross-site scripting SMTP attack"},{"id":"C","text":"SMTP spam messages leaving the network"},{"id":"D","text":"SSH administrative traffic on a busy network"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: SMTP spam messages leaving the network is correct. SMTP uses TCP port 25; excessive traffic could be indicative of internal e-mail spammers or spamming malware.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$While capturing network traffic, you notice excessive port 25 traffic leaving the network. What could this indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A UPS rack-mountable device measures 10U. Your rack can accommodate up to 42U. Currently, the rack contains three rows of 7U storage devices and two rows of 2U servers. How many rows of 10U UPS devices can be mounted in the server rack?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Two"},{"id":"B","text":"None"},{"id":"C","text":"One"},{"id":"D","text":"Four"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: One is correct. 42U � 21U (3 rows � 7U) � 4U (2 rows � 2U) leaves 17U remaining, so one row of 10U equipment can be accommodated in the rack.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A UPS rack-mountable device measures 10U. Your rack can accommodate up to 42U. Currently, the rack contains three rows of 7U storage devices and two rows of 2U servers. How many rows of 10U UPS devices can be mounted in the server rack?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which rack component ensures that cables don't get stretched when equipment is slid out from the rack?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Blade backplane"},{"id":"B","text":"Rail kit"},{"id":"C","text":"Cable management arm"},{"id":"D","text":"Blade enclosure"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: Cable management arm is correct. A cable management arm contains cables and folds behind equipment. When equipment is slid out, the arm extends, preventing cables from being stretched and pulled.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which rack component ensures that cables don't get stretched when equipment is slid out from the rack?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which type of RAM is commonly supported by server motherboards?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Non-ECC"},{"id":"B","text":"DDR6"},{"id":"C","text":"ECC"},{"id":"D","text":"DDR7"}]$patch$::jsonb, $patch$["A"]$patch$::jsonb, $patch$Correct Answer: ECC is correct. Error correcting code (ECC) memory can detect and correct memory errors and is commonly used in servers.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which type of RAM is commonly supported by server motherboards?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is troubleshooting a server that completed POST successfully but halts at a screen displaying 'Operating System Not Found.' The server has a single SSD connected to the motherboard's SATA controller. The SSD is visible in the BIOS/UEFI storage device list. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The SSD has failed and needs to be replaced immediately"},{"id":"b","text":"The boot order in BIOS/UEFI does not list the SSD as the first boot device, or the boot partition/MBR is corrupt"},{"id":"c","text":"The SATA controller has been disabled in the BIOS after the POST screen"},{"id":"d","text":"The server's RAM is faulty and cannot load the OS bootloader into memory"},{"id":"e","text":"The server is attempting to PXE boot and the network boot server is unavailable"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$When a server completes POST (confirming hardware is functional), the SSD is visible in BIOS (confirming the drive is detected), but the system reports 'Operating System Not Found,' the two most common causes are: (1) the SSD is not set as the primary boot device in BIOS/UEFI boot order, causing the system to look elsewhere, or (2) the Master Boot Record (MBR) or EFI System Partition on the SSD is corrupt or missing, so no valid boot loader can be found. A failed SSD would not appear in the BIOS device list. A disabled SATA controller would prevent the SSD from appearing in BIOS storage listings. Faulty RAM would cause POST failure or BSOD, not a clean 'OS Not Found' message. PXE boot attempts would show network boot messages, not 'Operating System Not Found.'$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/bootrec","label":"Microsoft - Fix MBR/Boot Issues with Windows Recovery"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is troubleshooting a server that completed POST successfully but halts at a screen displaying 'Operating System Not Found.' The server has a single SSD connected to the motherboard's SATA controller. The SSD is visible in the BIOS/UEFI storage device list. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server running Ubuntu Server 22.04 LTS is unable to mount an NFS share from a remote storage server. The command `mount -t nfs 192.168.10.50:/data /mnt/share` returns the error 'mount.nfs: access denied by server while mounting.' The NFS server is reachable via ping. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The NFS client package is not installed on the Ubuntu server"},{"id":"b","text":"The client server's IP address is not listed in the NFS server's /etc/exports file for that share"},{"id":"c","text":"The NFS protocol version is mismatched between client and server"},{"id":"d","text":"The /mnt/share directory does not exist on the client server"},{"id":"e","text":"The client server does not have a default gateway configured"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The error 'access denied by server while mounting' specifically indicates that the NFS server received the mount request but rejected it based on access controls. NFS exports are controlled by the `/etc/exports` file on the server, which lists which client IP addresses or subnets are allowed to access each share. If the client's IP is not listed, the server will deny the mount request. The NFS server is reachable via ping, ruling out network connectivity issues and default gateway problems. If the NFS client package were not installed, a different error would be returned locally before the request reached the server. A missing local mount point would produce a 'No such file or directory' error. An NFS version mismatch would produce a different negotiation error.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://ubuntu.com/server/docs/service-nfs","label":"Ubuntu Server - NFS Configuration"},{"url":"https://man7.org/linux/man-pages/man5/exports.5.html","label":"Linux man page - exports"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server running Ubuntu Server 22.04 LTS is unable to mount an NFS share from a remote storage server. The command `mount -t nfs 192.168.10.50:/data /mnt/share` returns the error 'mount.nfs: access denied by server while mounting.' The NFS server is reachable via ping. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which server form factor takes up the most space?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Tower"},{"id":"B","text":"Physical"},{"id":"C","text":"Blade"},{"id":"D","text":"Virtual"}]$patch$::jsonb, $patch$["A"]$patch$::jsonb, $patch$Correct Answer: Tower is correct. Tower servers take up the most space.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which server form factor takes up the most space?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator is called to investigate a server where the system event log shows repeated 'Disk Controller Error' entries correlating with periods of application unresponsiveness. The RAID array shows as healthy in the controller management software. Which is the BEST next troubleshooting step?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Replace the RAID controller card immediately without further investigation"},{"id":"b","text":"Check the physical SAS/SATA cables for damage, ensure proper seating, and inspect controller and backplane connections"},{"id":"c","text":"Rebuild the RAID array from scratch using the same drives to clear the error log"},{"id":"d","text":"Increase the RAID controller's cache memory to reduce I/O pressure"},{"id":"e","text":"Restore the server from the last known good backup and monitor for error recurrence"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Disk controller errors logged at the OS level, while the RAID controller management software shows the array as healthy, often indicate an issue at the physical connection layer rather than within the logical RAID configuration. Loose, damaged, or improperly seated SAS/SATA cables and backplane connections are a common and easy-to-overlook cause of intermittent controller errors. This is the appropriate next step following the troubleshooting methodology of checking physical-layer issues before replacing hardware. Replacing the RAID controller immediately skips logical diagnostic steps. Rebuilding the RAID array is destructive and premature. Increasing cache memory addresses performance, not error conditions. Restoring from backup does not address the underlying hardware issue.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://learn.microsoft.com/en-us/troubleshoot/windows-server/backup-and-storage/event-id-errors","label":"Microsoft - Event Viewer Disk Errors Troubleshooting"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator is called to investigate a server where the system event log shows repeated 'Disk Controller Error' entries correlating with periods of application unresponsiveness. The RAID array shows as healthy in the controller management software. Which is the BEST next troubleshooting step?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Windows Server 2022 domain controller is reporting that its system clock has drifted more than 5 minutes from the domain time source. This has caused Kerberos authentication failures for domain users. What is the correct way to resolve this issue while maintaining domain time hierarchy?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Manually set the system clock using the Date and Time control panel and disable the Windows Time service"},{"id":"b","text":"Configure the domain controller to sync with an external NTP source using w32tm /config and ensure the PDC Emulator syncs with a reliable external time source"},{"id":"c","text":"Reinstall the Windows Time service by removing and re-adding the Domain Services role"},{"id":"d","text":"Increase the Kerberos maximum clock skew tolerance to 30 minutes via Group Policy"},{"id":"e","text":"Force replicate Active Directory using repadmin /syncall to resolve the time discrepancy"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$In an Active Directory domain, the PDC Emulator FSMO role holder is the authoritative time source for all other domain members. The PDC Emulator should sync with a reliable external NTP source. Non-PDC domain controllers should sync from the PDC Emulator, and clients sync from domain controllers. The proper fix is to configure the time hierarchy correctly using `w32tm /config` on the PDC Emulator to point to an external NTP server, then allow the hierarchy to propagate. Manually setting the clock and disabling the Windows Time service breaks the domain time hierarchy. Reinstalling AD DS roles is unnecessary and disruptive. Increasing Kerberos clock skew tolerance is a workaround, not a fix, and 30 minutes exceeds security best practices. AD replication does not resolve time synchronization issues.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://learn.microsoft.com/en-us/windows-server/networking/windows-time-service/how-the-windows-time-service-works","label":"Microsoft - How the Windows Time Service Works"},{"url":"https://learn.microsoft.com/en-us/windows-server/networking/windows-time-service/configuring-systems-for-high-accuracy","label":"Microsoft - Configure Windows Time Service for the PDC Emulator"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Windows Server 2022 domain controller is reporting that its system clock has drifted more than 5 minutes from the domain time source. This has caused Kerberos authentication failures for domain users. What is the correct way to resolve this issue while maintaining domain time hierarchy?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An application server that was functioning normally has begun rejecting new user connections. Reviewing the server logs shows the error: 'Too many open files.' The server's CPU and memory utilization are both below 30%. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The server's disk partitions are full, preventing new file handles from being allocated"},{"id":"b","text":"The operating system's file descriptor limit has been reached by the application process"},{"id":"c","text":"The application has a memory leak that is exhausting available RAM"},{"id":"d","text":"The network stack is overwhelmed by too many simultaneous TCP connections from the internet"},{"id":"e","text":"The server's antivirus software is holding open scanned files and not releasing handles"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The error 'Too many open files' in Linux/Unix environments corresponds directly to the operating system's per-process or system-wide file descriptor (ulimit) limit being reached. Each network connection, open file, and socket consumes a file descriptor. When an application under heavy load exhausts this limit, it cannot open new connections or files. CPU and memory being low confirms the issue is not resource exhaustion in those areas. A full disk partition would produce 'No space left on device' errors. A memory leak would manifest as high memory utilization. Network stack overwhelm would produce different error messages. While antivirus software could contribute, the definitive cause is the file descriptor limit being hit.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man3/ulimit.3.html","label":"Linux man page - ulimit"},{"url":"https://www.kernel.org/doc/html/latest/admin-guide/sysctl/fs.html","label":"Linux - Understanding File Descriptors and ulimit"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An application server that was functioning normally has begun rejecting new user connections. Reviewing the server logs shows the error: 'Too many open files.' The server's CPU and memory utilization are both below 30%. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator is troubleshooting a server that intermittently loses connection to a fiber-attached SAN. The server logs show multi-path I/O (MPIO) failovers occurring at irregular intervals. FC switch logs show no errors. Which component should the administrator suspect FIRST?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The SAN array's cache battery"},{"id":"b","text":"The server's Host Bus Adapter (HBA) or its fiber optic cable/SFP"},{"id":"c","text":"The FC switch's zoning configuration"},{"id":"d","text":"The multipath software version on the server OS"},{"id":"e","text":"The SAN array's controller firmware"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$When MPIO failovers occur intermittently but FC switch logs show no errors, the fault is most likely on the server-side physical path between the HBA and the switch. A degraded SFP transceiver, a failing HBA, or a damaged fiber optic cable can cause intermittent link instability that triggers MPIO failover without generating switch-level errors, as the switch only logs the resulting link state change rather than the physical-layer signal degradation. The SAN cache battery and array controller firmware would affect all paths simultaneously and consistently. FC switch zoning errors would produce persistent connectivity failures, not intermittent MPIO failovers. Multipath software versions could cause policy issues but not physical path drops.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://learn.microsoft.com/en-us/windows-server/storage/file-server/troubleshoot/troubleshooting-smb-known-issues","label":"Microsoft - Multipath I/O Overview"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator is troubleshooting a server that intermittently loses connection to a fiber-attached SAN. The server logs show multi-path I/O (MPIO) failovers occurring at irregular intervals. FC switch logs show no errors. Which component should the administrator suspect FIRST?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$After a planned firmware update on a server's RAID controller, the server no longer recognizes the attached storage array. The RAID configuration was intact before the update. No hardware changes were made. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The firmware update reset the RAID controller configuration to factory defaults"},{"id":"b","text":"The storage array drives were placed in standby mode automatically during the update"},{"id":"c","text":"The new firmware version is incompatible with the existing RAID metadata format"},{"id":"d","text":"The SAS/SATA cables became loose during the firmware flashing process"},{"id":"e","text":"The RAID controller requires a new license key after a firmware upgrade"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$RAID controller firmware updates can change the metadata format or schema used to describe the RAID configuration. If the new firmware version is incompatible with the existing metadata written on the drives (e.g., a major version jump), the controller may not recognize the array. This is a documented risk with firmware updates on RAID controllers and is the most likely cause when no hardware changes were made. Firmware updates do not typically reset RAID configuration to factory defaults unless explicitly stated. Drives do not enter standby due to firmware flashing. Physical cables would not loosen during a firmware process. RAID controllers generally do not require new license keys after firmware updates.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.broadcom.com/support/knowledgebase","label":"Broadcom - RAID Controller Firmware Update Considerations"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$After a planned firmware update on a server's RAID controller, the server no longer recognizes the attached storage array. The RAID configuration was intact before the update. No hardware changes were made. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator receives alerts that a server's internal temperature is exceeding the warning threshold. Physical inspection reveals the server room air conditioning is functioning normally. Upon opening the server chassis, the administrator notices one of the internal case fans is not spinning. Which is the BEST immediate action?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Reduce server workload by migrating VMs to other hosts and schedule fan replacement during business hours"},{"id":"b","text":"Replace the failed fan as soon as possible to restore proper airflow and prevent component damage"},{"id":"c","text":"Point an external fan at the server's air vents as a permanent solution"},{"id":"d","text":"Increase the speed of the remaining fans via BIOS settings to compensate indefinitely"},{"id":"e","text":"Power off the server immediately and do not power it on until the room temperature drops"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A failed internal fan disrupts the designed airflow path within the server chassis, leading to hot spots that can damage CPUs, RAM, and other components. The best immediate action is to replace the failed fan as quickly as possible to restore proper thermal management. Many enterprise fans are hot-swappable, allowing replacement without powering down. While migrating VMs reduces thermal load, it does not fix the root cause. An external fan does not provide the directed airflow the chassis requires and is not a permanent or proper solution. BIOS fan speed adjustments are temporary workarounds and may not adequately compensate. Powering off the server is unnecessarily disruptive if the replacement fan can be installed promptly.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.comptia.org/blog/what-is-server-plus","label":"Server Thermal Management Best Practices"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator receives alerts that a server's internal temperature is exceeding the warning threshold. Physical inspection reveals the server room air conditioning is functioning normally. Upon opening the server chassis, the administrator notices one of the internal case fans is not spinning. Which is the BEST immediate action?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux server that hosts a production web application experiences slow disk I/O. An administrator suspects the issue is related to disk read/write performance. Which command provides the MOST relevant real-time disk I/O statistics per device?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"vmstat 1"},{"id":"b","text":"iostat -x 1"},{"id":"c","text":"sar -n DEV 1"},{"id":"d","text":"free -m"},{"id":"e","text":"ps aux --sort=-%cpu"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$`iostat -x 1` (from the sysstat package) provides extended I/O statistics per block device at a 1-second interval, including read/write throughput, IOPS, and device utilization percentages—making it the most directly relevant tool for diagnosing disk I/O bottlenecks. `vmstat 1` provides some I/O columns (bi/bo) but lacks per-device granularity. `sar -n DEV 1` reports network device statistics, not disk I/O. `free -m` shows memory usage. `ps aux --sort=-%cpu` shows process CPU usage. None of these alternatives give the per-disk extended I/O detail that `iostat -x` provides.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/iostat.1.html","label":"Linux man page - iostat"},{"url":"https://github.com/sysstat/sysstat","label":"sysstat project documentation"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux server that hosts a production web application experiences slow disk I/O. An administrator suspects the issue is related to disk read/write performance. Which command provides the MOST relevant real-time disk I/O statistics per device?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is troubleshooting a server that is logging correctable ECC memory errors approximately every 48 hours. The server has not crashed, but the errors are increasing in frequency over the past two weeks. What is the BEST course of action?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Continue monitoring the errors since ECC memory is designed to correct them automatically"},{"id":"b","text":"Identify the specific failing DIMM using memory diagnostics and replace it proactively"},{"id":"c","text":"Upgrade the server's BIOS to the latest version to improve ECC error handling"},{"id":"d","text":"Increase the server's virtual memory pagefile to compensate for the degraded RAM"},{"id":"e","text":"Restore the server from backup immediately and migrate to a different physical host"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$While ECC RAM can correct single-bit errors without data loss or crashes, an increasing frequency of correctable errors is a strong indicator of a degrading DIMM that will eventually produce uncorrectable errors, leading to system crashes or data corruption. The best practice is to use memory diagnostic tools (such as vendor-specific utilities or MemTest86) to identify the specific failing DIMM and replace it proactively during a maintenance window. Simply monitoring is dangerous given the escalating trend. A BIOS update does not repair degrading physical memory cells. Increasing the pagefile addresses virtual memory, not physical RAM faults. Restoring from backup is premature when the server is still operational and the root cause can be addressed directly.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://learn.microsoft.com/en-us/windows-hardware/drivers/whea/windows-hardware-error-architecture-overview","label":"Understanding ECC Memory Error Logging"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is troubleshooting a server that is logging correctable ECC memory errors approximately every 48 hours. The server has not crashed, but the errors are increasing in frequency over the past two weeks. What is the BEST course of action?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Users report that they can ping a Windows Server 2022 file server by IP address but cannot connect to shared folders using the server's hostname. DNS resolution from client machines returns no results for the server's hostname. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The server's Windows Firewall is blocking SMB traffic on port 445"},{"id":"b","text":"The server's A record has been deleted or was never created in DNS"},{"id":"c","text":"The SMB service has stopped on the file server"},{"id":"d","text":"The DHCP server has assigned the file server a new IP address"},{"id":"e","text":"The client machines have stale ARP cache entries pointing to the wrong MAC address"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$If clients can ping the server by IP but DNS resolution fails for the hostname, the issue is definitively within DNS. The server's A (Host) record is missing or was deleted, preventing name-to-IP resolution. A firewall blocking port 445 would allow ping by IP but prevent SMB connections; however, DNS resolution itself would still succeed. A stopped SMB service would allow hostname resolution but block file share access. A DHCP-assigned IP change would cause the A record to point to an old IP, but in this case DNS returns no results at all, indicating an absent record. A stale ARP cache would not affect DNS query responses.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://learn.microsoft.com/en-us/windows-server/networking/dns/troubleshoot/troubleshoot-dns-server","label":"Microsoft - DNS Troubleshooting"},{"url":"https://learn.microsoft.com/en-us/windows-server/networking/dns/manage-resource-records","label":"Microsoft - Understanding DNS Resource Records"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Users report that they can ping a Windows Server 2022 file server by IP address but cannot connect to shared folders using the server's hostname. DNS resolution from client machines returns no results for the server's hostname. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$After replacing a failed power supply unit in a server, the server powers on but shuts down again after approximately 30 seconds with no POST completion or beep codes. The replacement PSU is rated at 750W, whereas the original was rated at 1100W. What is the MOST likely cause of the shutdown?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The replacement PSU has a different connector type and is not fully seated"},{"id":"b","text":"The replacement PSU wattage is insufficient to power the server's components under load"},{"id":"c","text":"The server's BIOS does not recognize the new PSU's model number and is blocking boot"},{"id":"d","text":"The server requires two identical PSUs and the mismatched wattage disables both"},{"id":"e","text":"The PSU's fan has failed, causing an immediate thermal shutdown of the server"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A 750W PSU installed in a server whose components were designed to draw up to 1100W will trigger an over-current or under-voltage protection circuit when the system attempts to power all components, causing a protective shutdown within seconds. The BIOS does not validate PSU model numbers to block booting. Connector type incompatibility would have prevented the system from powering on at all. While PSU redundancy matching is important, the question describes a replacement scenario, not a redundant pair, and the primary failure mode here is wattage insufficiency. A PSU fan failure would not cause a shutdown within 30 seconds before thermal limits are reached.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.comptia.org/blog/what-is-server-plus","label":"Server Power Supply Sizing Guidelines"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$After replacing a failed power supply unit in a server, the server powers on but shuts down again after approximately 30 seconds with no POST completion or beep codes. The replacement PSU is rated at 750W, whereas the original was rated at 1100W. What is the MOST likely cause of the shutdown?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator observes that a server's CPU utilization consistently reaches 95–100% during business hours even though no new applications have been deployed. The server runs a Linux-based OS. Which command should the administrator use FIRST to identify the process consuming the most CPU?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"netstat -an"},{"id":"b","text":"df -h"},{"id":"c","text":"top"},{"id":"d","text":"lsblk"},{"id":"e","text":"ifconfig -a"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$The `top` command provides a real-time dynamic view of running processes sorted by CPU usage by default, making it the ideal first step to identify which process is consuming the most CPU on a Linux system. `netstat -an` shows network connections, not CPU usage. `df -h` reports disk space utilization. `lsblk` lists block devices. `ifconfig -a` shows network interface configuration. None of these alternatives address CPU performance troubleshooting.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/top.1.html","label":"Linux man page - top"},{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator observes that a server's CPU utilization consistently reaches 95–100% during business hours even though no new applications have been deployed. The server runs a Linux-based OS. Which command should the administrator use FIRST to identify the process consuming the most CPU?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is troubleshooting intermittent network connectivity on a server. The server has two NICs teamed together for redundancy. Connectivity drops for approximately 10 seconds every few hours. Reviewing the switch logs shows no errors on the switch ports. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The switch firmware is incompatible with the NIC teaming mode configured on the server"},{"id":"b","text":"The NIC teaming heartbeat interval is misconfigured and causing unnecessary failovers"},{"id":"c","text":"One physical NIC in the team has a failing transceiver causing periodic link drops that trigger failover"},{"id":"d","text":"The IP address of the server is conflicting with another device on the same subnet"},{"id":"e","text":"The network cable connecting the primary NIC is too long and exceeds the Cat6 specification"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$Intermittent 10-second connectivity drops with no switch-side errors in a NIC team environment are a classic symptom of a failing physical NIC or transceiver. When one NIC drops link intermittently, the teaming software initiates a failover, causing the brief connectivity gap. Switch logs would not necessarily capture transient physical-layer events on the server side. A misconfigured heartbeat would produce much more frequent and consistent failovers. An IP conflict would cause ARP-related issues and not timed periodic drops. Cat6 supports 100m runs, and a length violation would cause persistent errors rather than intermittent drops.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://learn.microsoft.com/en-us/windows-server/networking/technologies/nic-teaming/nic-teaming","label":"Microsoft - NIC Teaming Overview"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is troubleshooting intermittent network connectivity on a server. The server has two NICs teamed together for redundancy. Connectivity drops for approximately 10 seconds every few hours. Reviewing the switch logs shows no errors on the switch ports. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Windows Server 2022 server suddenly reboots unexpectedly and displays a Stop error (BSOD) referencing MEMORY_MANAGEMENT with bug check code 0x0000001A. Which action should the administrator take FIRST to diagnose this issue?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Replace the system board immediately as it is the most common cause of this error"},{"id":"b","text":"Run the Windows Memory Diagnostic tool or MemTest86 to test physical RAM"},{"id":"c","text":"Restore the server from the most recent backup and monitor for recurrence"},{"id":"d","text":"Reinstall the Windows Server operating system to clear corrupt system files"},{"id":"e","text":"Update the server's BIOS/UEFI firmware to the latest available version"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Stop code 0x0000001A (MEMORY_MANAGEMENT) directly indicates a problem with the physical memory subsystem or memory management functions. The correct first diagnostic step follows the troubleshooting methodology of identifying the problem before taking corrective action; running Windows Memory Diagnostic or MemTest86 will confirm whether faulty RAM is the root cause. Replacing the system board before testing RAM skips logical diagnostic steps. Restoring from backup does not address a hardware fault. Reinstalling the OS is premature. BIOS updates may help but are not the first step when a memory-specific stop code is reported.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://learn.microsoft.com/en-us/windows-hardware/drivers/debugger/bug-check-0x1a--memory-management","label":"Microsoft - Bug Check 0x1A: MEMORY_MANAGEMENT"},{"url":"https://learn.microsoft.com/en-us/windows-server/administration/windows-commands/mdsched","label":"Windows Memory Diagnostic Tool"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Windows Server 2022 server suddenly reboots unexpectedly and displays a Stop error (BSOD) referencing MEMORY_MANAGEMENT with bug check code 0x0000001A. Which action should the administrator take FIRST to diagnose this issue?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$During routine maintenance, an administrator receives an alert that one of four drives in a RAID 5 array has failed. Before a replacement drive arrives, a second drive in the same array also fails. What is the current state of the data on the array?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Data is fully accessible in a degraded state because RAID 5 tolerates two drive failures"},{"id":"b","text":"Data is still accessible because the array automatically switched to RAID 1"},{"id":"c","text":"Data is completely inaccessible because RAID 5 can only tolerate one drive failure"},{"id":"d","text":"Data is accessible in read-only mode while the controller attempts a rebuild"},{"id":"e","text":"Data is partially accessible depending on which stripes the failed drives belong to"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$RAID 5 uses distributed parity and can tolerate the failure of exactly one drive at a time. When a second drive fails before the array is rebuilt, the parity data is insufficient to reconstruct the missing data, rendering the entire array inaccessible. RAID 5 does not automatically migrate to RAID 1, does not support a read-only rebuild mode for double failures, and does not provide selective stripe access when two drives have failed. RAID 6 would be required for tolerance of two simultaneous drive failures.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.comptia.org/blog/raid-levels-explained","label":"RAID Levels Explained - CompTIA"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$During routine maintenance, an administrator receives an alert that one of four drives in a RAID 5 array has failed. Before a replacement drive arrives, a second drive in the same array also fails. What is the current state of the data on the array?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator notices that a server running multiple virtual machines suddenly becomes unresponsive. The physical server's power LED is green and the network switch shows active link lights. After attaching a local keyboard and monitor, the administrator sees a blank screen with a blinking cursor and no boot activity. Which is the MOST likely cause?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The server's NIC has failed and the management network is unavailable"},{"id":"b","text":"The hypervisor boot partition is corrupt or missing, preventing OS load"},{"id":"c","text":"A failed VM snapshot caused all guest VMs to lock up simultaneously"},{"id":"d","text":"The UPS is sending a shutdown signal over USB to the server"},{"id":"e","text":"The server's IPMI/BMC firmware requires an update"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A blinking cursor on a blank screen with no boot activity after POST indicates the bootloader or boot partition cannot be found or is corrupt. The server's power LED being green confirms hardware is energized, and active link lights rule out a NIC failure as the primary symptom. A failed VM snapshot would not prevent the hypervisor OS from booting, and a UPS shutdown signal would have powered off the server rather than leaving it in a blinking-cursor state. BMC firmware updates would not cause a boot failure on their own.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.comptia.org/blog/what-is-server-plus","label":"CompTIA Server+ Troubleshooting Boot Issues"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator notices that a server running multiple virtual machines suddenly becomes unresponsive. The physical server's power LED is green and the network switch shows active link lights. After attaching a local keyboard and monitor, the administrator sees a blank screen with a blinking cursor and no boot activity. Which is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is hardening a newly deployed server in accordance with the principle of least privilege. Which action BEST applies this principle to the server's local user accounts and services?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Rename the built-in Administrator account and assign it a complex password"},{"id":"b","text":"Disable all accounts not needed for operations and ensure services run under accounts with only the permissions required for their function"},{"id":"c","text":"Enable account lockout policies after three failed login attempts for all user accounts"},{"id":"d","text":"Configure all services to run under the built-in local Administrator account to simplify permissions management"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The principle of least privilege states that every user, service, and process should have only the minimum permissions necessary to perform its function and nothing more. Disabling unneeded accounts reduces the attack surface, and assigning services dedicated accounts with narrowly scoped permissions directly implements least privilege. Option A (renaming the Administrator account) is a useful obscurity measure but does not reduce the actual permissions or access rights granted — it does not implement least privilege. Option C (account lockout) is a valid account security hardening measure, but it addresses brute-force protection rather than privilege minimization, so it is not the best example of least privilege. Option D directly violates the principle of least privilege by running all services under an Administrator account, granting them far more access than they need.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives – Server Hardening"},{"url":"https://csrc.nist.gov/publications/detail/sp/800-123/final","label":"NIST SP 800-123: Guide to General Server Security"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is hardening a newly deployed server in accordance with the principle of least privilege. Which action BEST applies this principle to the server's local user accounts and services?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company's disaster recovery plan specifies an RTO of 4 hours for its primary application server. After a failure occurs, the team discovers that restoring from tape backup takes approximately 6 hours. Which solution would BEST bring the recovery process into compliance with the stated RTO?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Switch from full backups to incremental backups to reduce the backup window"},{"id":"b","text":"Implement a warm standby server that is periodically synchronized with the production server"},{"id":"c","text":"Increase the tape backup frequency from weekly to nightly"},{"id":"d","text":"Store tape backups in a geographically separate off-site location"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A warm standby is a partially configured standby server that is kept up-to-date with periodic data synchronization. In the event of a failure, the warm standby can be promoted to production, typically within minutes to a couple of hours — well within a 4-hour RTO. Option A (switching to incremental backups) reduces backup time but actually increases restore time because all incremental sets must be applied sequentially, worsening the RTO. Option C (nightly tape backups) improves the RPO by reducing potential data loss but does not reduce the 6-hour restoration time, so the RTO is still violated. Option D (off-site tape storage) improves geographic redundancy and protects against site-level disasters but adds transport time to the restore process, making the RTO even harder to meet.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives – Disaster Recovery Concepts"},{"url":"https://csrc.nist.gov/publications/detail/sp/800-34/rev-1/final","label":"NIST SP 800-34 Rev. 1: Contingency Planning Guide for Federal Information Systems"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company's disaster recovery plan specifies an RTO of 4 hours for its primary application server. After a failure occurs, the team discovers that restoring from tape backup takes approximately 6 hours. Which solution would BEST bring the recovery process into compliance with the stated RTO?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which type of power connector is commonly used in North America?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"NUMA"},{"id":"B","text":"NEMA"},{"id":"C","text":"Edison"},{"id":"D","text":"Einstein"}]$patch$::jsonb, $patch$["A"]$patch$::jsonb, $patch$Correct Answer: NEMA is correct. The National Electronic Manufacturers Association (NEMA) plug connector is common in North America.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which type of power connector is commonly used in North America?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to ensure that a server's operating system drive is protected against data exposure if the physical drive is removed from the datacenter and taken off-premises. No additional hardware security modules are available. Which security control BEST addresses this threat?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Enable BIOS/UEFI password protection on the server"},{"id":"b","text":"Implement full-disk encryption on the OS drive using software-based encryption"},{"id":"c","text":"Configure RAID 1 mirroring across two drives in the server"},{"id":"d","text":"Enable Secure Boot in the server's UEFI firmware settings"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Full-disk encryption (FDE) ensures that all data written to the drive is encrypted at rest. If the drive is physically removed, the data remains unreadable without the correct encryption key, directly mitigating the threat of data exposure from drive theft. Option A (BIOS/UEFI password) protects the boot process on the original system but does not encrypt the data on the disk itself — the drive can be read in another system. Option C (RAID 1) provides redundancy and fault tolerance but offers no protection against data exposure if a drive is removed. Option D (Secure Boot) validates the integrity of the boot process to prevent unsigned code from executing, but does not encrypt data at rest.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives – Data Security"},{"url":"https://csrc.nist.gov/publications/detail/sp/800-111/final","label":"NIST SP 800-111: Guide to Storage Encryption Technologies for End User Devices"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to ensure that a server's operating system drive is protected against data exposure if the physical drive is removed from the datacenter and taken off-premises. No additional hardware security modules are available. Which security control BEST addresses this threat?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator is designing a backup strategy for a critical database server that requires minimal data loss and must be able to recover to any point within the last 24 hours. The organization can tolerate a maximum of 1 hour of data loss. Which backup approach BEST satisfies both requirements?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"A full backup performed once per week with no supplemental backups"},{"id":"b","text":"A full backup performed nightly combined with transaction log backups every 30 minutes"},{"id":"c","text":"An incremental backup performed every 24 hours with no full backup baseline"},{"id":"d","text":"A differential backup performed every 12 hours with a full backup once per month"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A nightly full backup combined with transaction log backups every 30 minutes satisfies both requirements: the 30-minute log backup interval keeps data loss well within the 1-hour RPO (Recovery Point Objective), and the combination of the full backup plus the log chain allows point-in-time recovery within the last 24 hours. Option A fails because a weekly full with no supplemental backups could result in up to 7 days of data loss. Option C is invalid because an incremental backup requires a full baseline to restore against. Option D uses differentials every 12 hours, which could still result in up to 12 hours of data loss, violating the 1-hour RPO requirement.$patch$, $patch$Security and Disaster Recovery$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives – Security and Disaster Recovery"},{"url":"https://www.comptia.org/training/books/server-sk0-005-study-guide","label":"CompTIA Server+ Study Guide: Backup Types and Recovery Strategies"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator is designing a backup strategy for a critical database server that requires minimal data loss and must be able to recover to any point within the last 24 hours. The organization can tolerate a maximum of 1 hour of data loss. Which backup approach BEST satisfies both requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator needs to ensure that a Linux server automatically mounts a remote NFS share every time the system boots. The administrator has already verified that the NFS share is accessible from the server. Which file should be modified to persist the NFS mount across reboots?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"/etc/hosts"},{"id":"b","text":"/etc/fstab"},{"id":"c","text":"/etc/mtab"},{"id":"d","text":"/etc/exports"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$/etc/fstab (filesystem table) is the correct file to modify when you want a mount — including remote NFS shares — to be automatically applied at boot time. Each line in /etc/fstab defines a filesystem, its mount point, type, and options; the OS reads this file during startup and mounts all entries accordingly. /etc/hosts maps hostnames to IP addresses and is unrelated to mounting. /etc/mtab is a runtime file maintained by the kernel that lists currently mounted filesystems; it is not intended to be edited manually and does not persist mounts across reboots. /etc/exports is used on the NFS *server* side to define which directories are shared and to which clients — not on the client side for mounting.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/assembly_mounting-file-systems_managing-file-systems#proc_persistently-mounting-file-systems-using-etc-fstab_assembly_mounting-file-systems","label":"Red Hat Documentation – Managing the /etc/fstab file"},{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator needs to ensure that a Linux server automatically mounts a remote NFS share every time the system boots. The administrator has already verified that the NFS share is accessible from the server. Which file should be modified to persist the NFS mount across reboots?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A technician is configuring a new server's out-of-band management interface (BMC/iDRAC/iLO) and needs to ensure it is accessible for remote administration without relying on the server's primary operating system. Which of the following network configurations BEST supports this requirement?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Connect the BMC to the same network segment as the server's primary production NICs and assign it an IP in the same subnet"},{"id":"b","text":"Connect the BMC to a dedicated out-of-band management network with its own IP address, VLAN, and restricted access controls"},{"id":"c","text":"Configure the BMC to share the server's primary NIC using NIC teaming for high availability"},{"id":"d","text":"Disable the BMC network interface and use serial-over-LAN exclusively for all remote management"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Connecting the BMC/iDRAC/iLO to a dedicated out-of-band management network on its own VLAN with restricted access controls is the best practice. This ensures management access is available even when the OS is unresponsive or the server is powered off, and isolates management traffic from production traffic for security. Placing BMC on the production network (A) exposes the powerful management interface to a wider attack surface. Sharing a primary NIC (C) creates a dependency on the OS network stack, defeating the purpose of out-of-band management. Disabling the network interface (D) severely limits remote management capabilities and does not support full KVM-over-IP functionality.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.dmtf.org/standards/redfish","label":"DMTF Redfish – Out-of-Band Management Overview"},{"url":"https://www.dell.com/support/manuals/en-us/idrac9-lifecycle-controller-v6.x-series/idrac9_6.xx_ug/network-settings","label":"Dell iDRAC9 User's Guide – Network Configuration"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A technician is configuring a new server's out-of-band management interface (BMC/iDRAC/iLO) and needs to ensure it is accessible for remote administration without relying on the server's primary operating system. Which of the following network configurations BEST supports this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator needs to replace a failed power supply unit (PSU) in a server that supports redundant hot-swap power supplies. The server is currently running in production. Which of the following describes the correct procedure?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Power down the server, remove both PSUs simultaneously, install the new PSU, then power the server back on"},{"id":"b","text":"Identify the failed PSU using the fault indicator, remove it without powering down the server, and insert the replacement PSU"},{"id":"c","text":"Power down the server, replace the failed PSU, then power the server back on"},{"id":"d","text":"Leave the failed PSU in place and order a replacement, as the redundant PSU will handle the load indefinitely"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Hot-swap redundant PSU designs allow a failed unit to be removed and replaced while the server remains powered on and operational, because the remaining PSU carries the full load. The fault indicator LED identifies which unit has failed. This is the primary operational advantage of redundant PSU configurations. Powering down is unnecessary and causes unplanned downtime (A and C). Leaving the failed PSU indefinitely (D) eliminates redundancy and leaves the server vulnerable to a total power failure if the remaining PSU also fails.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://support.hpe.com/hpesc/public/docDisplay?docId=emr_na-c04443835","label":"HPE Hot Plug Power Supply User Guide"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator needs to replace a failed power supply unit (PSU) in a server that supports redundant hot-swap power supplies. The server is currently running in production. Which of the following describes the correct procedure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When installing a server into a rack using rail kits, a technician discovers that the rails included with the server are not compatible with the existing rack posts. Which of the following is the FIRST step the technician should take to resolve this issue?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Force the rail kit into place using additional mounting hardware from another server model"},{"id":"b","text":"Verify the rack post hole pattern (square, round, or threaded) and rack unit width against the rail kit specifications"},{"id":"c","text":"Mount the server directly to the rack using zip ties as a temporary measure"},{"id":"d","text":"Return the entire server to the vendor and request a compatible model"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The first troubleshooting step is always to verify compatibility by checking the rack post hole pattern (square-hole, round-hole, or threaded) and confirming the rack's internal width matches the rail kit specifications. Many vendors offer universal or adjustable rail kits, and the correct kit may simply need to be ordered. Forcing incompatible hardware (A) risks damaging the rack or server and creates a safety hazard. Zip ties (C) are not an appropriate structural mounting solution for heavy server equipment. Returning the server (D) is premature before verifying whether a compatible rail kit is available.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.dell.com/support/kbdoc/en-us/000137048/rail-compatibility-guide-for-poweredge-servers","label":"Dell Technologies Rail Compatibility Guide"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When installing a server into a rack using rail kits, a technician discovers that the rails included with the server are not compatible with the existing rack posts. Which of the following is the FIRST step the technician should take to resolve this issue?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server's hot-swap drive bay indicator LEDs show a solid amber light on one of the installed drives. According to standard LED status conventions, what does this MOST likely indicate?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The drive is operating normally and is fully accessible"},{"id":"b","text":"The drive is actively rebuilding as part of a RAID array"},{"id":"c","text":"The drive has failed or is experiencing a fault condition"},{"id":"d","text":"The drive bay is empty and awaiting a drive to be installed"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$On most server platforms, a solid amber (or orange) drive bay LED indicates a drive fault or failure condition, alerting the administrator that the drive needs attention or replacement. A green LED typically indicates normal operation (A). A blinking or alternating LED pattern, often green/amber, typically signals RAID rebuild activity (B). An empty bay either shows no LED activity or a specific pattern depending on the vendor, but not a solid amber (D). Always consult vendor-specific documentation, as conventions can vary slightly, but solid amber for fault is the industry-standard convention.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://support.hpe.com/hpesc/public/docDisplay?docId=a00045916en_us","label":"HPE ProLiant Server LED Indicators Guide"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server's hot-swap drive bay indicator LEDs show a solid amber light on one of the installed drives. According to standard LED status conventions, what does this MOST likely indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A technician is installing a PCIe NVMe expansion card into a server that currently has several occupied PCIe slots. The card is a PCIe x4 device. The server has one PCIe x16 slot, one PCIe x8 slot, and one PCIe x4 slot available. The x4 slot is already occupied. Which of the following is the BEST slot to use for the NVMe card?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The PCIe x16 slot, because it provides the fastest possible interface"},{"id":"b","text":"The PCIe x8 slot, because it is electrically compatible and preserves the x16 slot for higher-bandwidth devices"},{"id":"c","text":"The PCIe x4 slot, even though it is occupied, by using a PCIe riser"},{"id":"d","text":"Any available USB slot using a PCIe-to-USB adapter"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A PCIe x4 card is backward compatible with x8 and x16 slots and will operate at x4 speeds regardless. Using the x8 slot is the best choice because it meets the card's electrical requirements while preserving the x16 slot for graphics, high-bandwidth storage controllers, or network adapters that can actually utilize the additional lanes. Using the x16 slot (A) wastes valuable high-bandwidth resources. A PCIe riser sharing an occupied slot (C) introduces complexity and potential compatibility issues. USB adapters (D) are entirely unsuitable for NVMe storage performance requirements.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://pcisig.com/specifications","label":"PCI-SIG PCIe Base Specification Overview"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A technician is installing a PCIe NVMe expansion card into a server that currently has several occupied PCIe slots. The card is a PCIe x4 device. The server has one PCIe x16 slot, one PCIe x8 slot, and one PCIe x4 slot available. The x4 slot is already occupied. Which of the following is the BEST slot to use for the NVMe card?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$During a server rack installation, a technician needs to ensure proper weight distribution and airflow management. Which of the following practices BEST addresses both concerns simultaneously?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Install the heaviest servers at the top of the rack and use blanking panels in empty slots"},{"id":"b","text":"Install the heaviest servers at the bottom of the rack and use blanking panels in all empty slots"},{"id":"c","text":"Distribute servers evenly throughout the rack regardless of weight and leave empty slots open for airflow"},{"id":"d","text":"Install the heaviest servers in the middle of the rack and use cable management arms to direct airflow"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Placing the heaviest servers at the bottom of the rack lowers the center of gravity, reducing tip-over risk and improving rack stability. Blanking panels in empty slots prevent hot exhaust air from recirculating into equipment intake areas, maintaining proper front-to-back airflow. Installing heavy equipment at the top (A) raises the center of gravity dangerously. Leaving empty slots open (C) allows hot-air bypass and recirculation. Middle placement (D) still leaves the rack top-heavy relative to best practice.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.se.com/us/en/download/document/SPD_VAVR-5SZTMG_EN/","label":"APC by Schneider Electric – Rack Airflow Best Practices White Paper"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$During a server rack installation, a technician needs to ensure proper weight distribution and airflow management. Which of the following practices BEST addresses both concerns simultaneously?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A server administrator is planning to add RAM to a production server that currently has four 16 GB DDR4 RDIMMs installed across eight available memory slots. The server documentation specifies that memory must be installed in matched pairs for optimal performance. Which of the following configurations BEST maintains optimal memory performance?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Install two additional 16 GB RDIMMs in any two available slots"},{"id":"b","text":"Install four additional 16 GB RDIMMs in the correct channel-paired slots per the server documentation"},{"id":"c","text":"Install two 32 GB RDIMMs in the first two available slots to maximize capacity"},{"id":"d","text":"Remove the existing DIMMs and replace all eight slots with 32 GB RDIMMs"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Installing four additional 16 GB RDIMMs in the correct channel-paired slots maintains dual-channel or quad-channel memory operation, which is required for optimal throughput. Server memory controllers operate most efficiently when channels are symmetrically populated. Adding only two DIMMs (A) could create an unbalanced channel configuration. Installing mismatched capacity RDIMMs (C) breaks channel symmetry and can degrade performance. Replacing all DIMMs (D) is costly and disruptive and not necessary when matched expansion is possible.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.jedec.org/standards-documents/docs/jesd79-4b","label":"JEDEC DDR4 SDRAM Standard Overview"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A server administrator is planning to add RAM to a production server that currently has four 16 GB DDR4 RDIMMs installed across eight available memory slots. The server documentation specifies that memory must be installed in matched pairs for optimal performance. Which of the following configurations BEST maintains optimal memory performance?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A technician is installing a new dual-processor server and notices that after seating both CPUs, the system only recognizes one processor in the BIOS. The CPUs are identical models and both are firmly seated. Which of the following is the MOST likely cause of this issue?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The second CPU socket is disabled in the BIOS/UEFI firmware settings"},{"id":"b","text":"The two CPUs have mismatched stepping versions"},{"id":"c","text":"The server chassis does not support dual-processor configurations"},{"id":"d","text":"The thermal paste was applied incorrectly to the first CPU"}]$patch$::jsonb, $patch$["a"]$patch$::jsonb, $patch$When identical CPUs are installed and only one is recognized, the most common cause is that the second CPU socket has been disabled in BIOS/UEFI settings. Many server platforms ship with secondary sockets disabled by default and require explicit enablement. Mismatched stepping (B) can cause instability but both CPUs would typically still be detected. A chassis compatibility issue (C) would be identified before installation. Thermal paste application (D) affects cooling, not CPU detection.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ SK0-005 Exam Objectives"},{"url":"https://www.intel.com/content/www/us/en/support/articles/000005954/processors.html","label":"Intel Multi-Processor Specification"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A technician is installing a new dual-processor server and notices that after seating both CPUs, the system only recognizes one processor in the BIOS. The CPUs are identical models and both are firmly seated. Which of the following is the MOST likely cause of this issue?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which type of tool can be used to verify file integrity?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Defragmentation"},{"id":"B","text":"Hashing"},{"id":"C","text":"Spoofing"},{"id":"D","text":"ACL"}]$patch$::jsonb, $patch$["B"]$patch$::jsonb, $patch$Correct Answer: Hashing is correct. Hashing tools take input data fed into an algorithm that results in a unique value, the hash. This can be repeated in the future to detect changes to files.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which type of tool can be used to verify file integrity?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which type of fiber-optic cable should be used over shorter distances?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Long-mode"},{"id":"B","text":"Short-mode"},{"id":"C","text":"Single-mode"},{"id":"D","text":"Multi-mode"}]$patch$::jsonb, $patch$["D"]$patch$::jsonb, $patch$Correct Answer: Multi-mode is correct. Multi-mode fiber-optic cabling is best suited for distances under 2 kilometers.$patch$, $patch$Server Hardware Installation and Management$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P3$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which type of fiber-optic cable should be used over shorter distances?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Using a packet sniffer, you notice traffic destined for TCP port 389. What type of traffic is this?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"POP3"},{"id":"B","text":"FTP"},{"id":"C","text":"LDAP"},{"id":"D","text":"SMTP"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: LDAP is correct. The Lightweight Directory Access Protocol (LDAP) is a network directory protocol that normally listens on TCP port 389.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
