INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which two types of file systems enable the configuration of local file system permissions? (Choose two.)$patch$, 'MULTI'::"QType", $patch$[{"id":"A","text":"FAT32"},{"id":"B","text":"ReFS"},{"id":"C","text":"FAT"},{"id":"D","text":"NTFS"}]$patch$::jsonb, $patch$["A","C"]$patch$::jsonb, $patch$Correct Answers: NTFS and ReFS are correct. Local file system permissions can be set on NTFS and ReFS file systems.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
