INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your company hosts a busy web server. You have been asked to increase the response time of the web site. What should you configure?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Failover clustering"},{"id":"B","text":"IPv6"},{"id":"C","text":"Load balancing"},{"id":"D","text":"Virtualization"}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: Load balancing is correct. A load balancer accepts users' requests for service and directs those requests to the least-busy back-end server to improve response time.$patch$, $patch$Server Administration$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P4$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your company hosts a busy web server. You have been asked to increase the response time of the web site. What should you configure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$User Christine complains that she can no longer print to any office printer from her Windows station. Other users do not have any printing issues. What is the first thing you should do on Christine's station?$patch$, 'SINGLE'::"QType", $patch$[{"id":"A","text":"Reboot all printers."},{"id":"B","text":"Reboot the station."},{"id":"C","text":"Restart the print spooler service."},{"id":"D","text":"Reconfigure all printers."}]$patch$::jsonb, $patch$["C"]$patch$::jsonb, $patch$Correct Answer: Restart the print spooler service is correct. Restarting the print spooler service is quicker than rebooting.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/server","label":"CompTIA Server+ exam objectives"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:sk0-005-prior-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$SK0-005-P4$patch$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$User Christine complains that she can no longer print to any office printer from her Windows station. Other users do not have any printing issues. What is the first thing you should do on Christine's station?$patch$);
